mapper.select:
SELECT ci.id, ci.category_id, cc.category_name, cc.category_code, ci.item_code, ci.item_name, ci.item_description, ci.deduct_mode, ci.default_deduct_score, ci.min_deduct_score, ci.max_deduct_score, ci.check_points, ci.sort_order, ci.status, ci.created_at, ci.updated_at FROM check_items ci LEFT JOIN check_categories cc ON ci.category_id = cc.id AND cc.deleted = 0
ci.deleted = 0
AND ci.item_name LIKE CONCAT('%', #{query.itemName}, '%')
AND ci.item_code LIKE CONCAT('%', #{query.itemCode}, '%')
AND ci.category_id = #{query.categoryId}
AND ci.deduct_mode = #{query.deductMode}
AND ci.status = #{query.status}
ORDER BY ci.category_id ASC, ci.sort_order ASC, ci.created_at DESC
